<template>
    <ul v-if="children && children.length">
      <li v-for="(node, index) in children" :key="node.serviceId">
        <span
          :class="{
            collapsed: isCollapsed(node.serviceId),
            expanded: !isCollapsed(node.serviceId),
            grandparent: node.isParentNode,
            'globalchartli': node.nodeName && node.nodeName.includes('GLOBAL~')
          }"
          @click="toggle(node.serviceId)"
          :data-content="getDataContent(node, index)"
        >
          <div class="pullleft nodecount">
            <div class="pullleft textaligncenter width_100 fontbold black_font12">
              {{ node.serviceName }}
            </div>
            <div class="pullleft textalignleft condition_overflow_chart">
              {{ getcondition(node) }}
            </div>
          </div>
        </span>
  
        <flow-children
          v-if="node.children && node.children.length && !isCollapsed(node.serviceId)"
          :children="node.children"
          :isBillingType="isBillingType"
        />
      </li>
    </ul>
  </template>
  
  <script>
  export default {
    name: 'FlowChildren',
    props: {
      children: {
        type: Array,
        required: true
      },
      isBillingType: {
        type: Boolean,
        required: false,
        default: false
      }
    },
    data() {
      return {
        collapsedMap: {}
      };
    },
    methods: {
      isCollapsed(id) {
        return !!this.collapsedMap[id];
      },
      toggle(id) {
        this.$set(this.collapsedMap, id, !this.collapsedMap[id]);
      },
      getDataContent(node, index) {
        // Only apply special handling when isBillingType is true
        if (this.isBillingType === true) {
          // Handle GLOBAL nodes
          if (node.nodeName && (node.nodeName.includes('GLOBAL~') || node.nodeName.toUpperCase() === 'GLOBAL')) {
            return `Global ${index + 1}`;
          }
          // Handle numeric node names (like "0") - show as empty or custom text
          if (node.nodeName === '0' || node.nodeName === 0) {
            return ''; // Or return custom design text if needed
          }
          // Filter out Start nodes
          if (node.serviceId === 'start' || node.nodeName === 'Start' || node.serviceName === 'Start') {
            return '';
          }
        }
        // For other nodes or when isBillingType is false, show Rule with nodeName
        return node.nodeName ? `Rule ${node.nodeName}` : '';
      },
      getTitle(node) {
        return node.isLeafNode ? `${node.condition}  LeafNode` : node.condition;
      },
      getcondition(node) {
        return node.isLeafNode ? `${node.condition}  LeafNode` : node.condition;
      }
    }
  };
  </script>
  