        recalculateRules(rulesArray, parentVersion = null) {
            if (!Array.isArray(rulesArray)) return;
            let localCounter = 1;
            rulesArray.forEach((rule) => {
                if (rule.ruleCondition && rule.ruleCondition.nodeName === 'GLOBAL') return;
                if (rule.version === 'GLOBAL') return;
                const newVersion = parentVersion ? `${parentVersion}.${localCounter}` : `${localCounter}`;
                rule.version = newVersion;
                rule.ruleName = `Rule ${newVersion}`;
                rule.ruleDisplayOrder = localCounter;
                rule.parent = parentVersion;
                if (rule.ruleCondition) {
                    rule.ruleCondition.nodeName = newVersion;
                }
                if (rule.rules && rule.rules.length > 0) {
                    this.recalculateRules(rule.rules, newVersion);
                }
                localCounter++;
            });
