        //     this.rules.splice(insertIndex, 0, newRule);
        //     this.redefineRuleVersions(rl.parent);
        // },

        redefineRuleVersions: function (prnt) {
            let localIndex = 1;
            this.rules.forEach(item => {
                if(item.version === 'GLOBAL') return; // skip GLOBAL

                item.ruleDisplayOrder = localIndex;
                if (prnt == null) {
                    item.version = `${localIndex}`;
                    item.ruleName = `Rule ${localIndex}`;
                } else {
                    item.version = `${prnt}.${localIndex}`;
                    item.ruleName = `Rule ${prnt}.${localIndex}`;
                }

                localIndex++;
            });
        }
    },
}
